INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 102111, 1, 1, "覚えていてくれただけでうれしいのに、\nこんなに豪華な用意までしてもらって……", 10, 11514, 11, 11514073, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 11514, 91, 11514074, "");
