INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 102711, 1, 1, "………………そう、ですか。\nそれならありがたく\nいただくことにしましょう。", 10, 16614, 11, 16614078, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 16614, 91, 16614079, "");
