INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100411, 1, 1, "やったー、ありがとー！\nそれにしても、おっきい～……\n運ぶの、大変じゃなかった？", 10, 17714, 11, 17714067, 0.5);
