INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_18814", "", 0, "vo_wac_18814_005", 0, 18814, 21, 18814095, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 102711, 1, 1, "ところで。\nどうしてナナカさんが欲しがっている\n限定品を、あなた様が正確に把握して\nいらっしゃったのでしょう……？", 10, 18814, 11, 18814096, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 18814, 91, 18814097, "");
