INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100111, 1, 1, "うわぁ～……！\nこの誕生日ケーキ、\nみんなが用意してくれたの！？\nすごくおいしそうだよ～♪", 10, 19414, 11, 19414058, 0.5);
