INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100211, 1, 1, "騎士クンとレイちゃん、\nみんなで手作りしたの♪\nお店で買った方がおいしいかもって、\nちょっと迷ったりもしたんだけど……", 10, 19414, 11, 19414063, 0.5);
