INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 105511, 1, 1, "誕生日にそんなことされて喜ぶのは、\nクウカさんだけだと思います……", 10, 19814, 11, 19814086, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 19814, 91, 19814087, "");
