INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100811, 1, 1, "ちなみに、このケーキは美しいボクと\nギルドの仲間たち、それといつもの\nこの人で選んだんだ。主にボクの\n顔を思い浮かべつつ味わってよね♪", 10, 19814, 11, 19814096, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 19814, 91, 19814097, "");
