INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 103011, 1, 1, "なんと、ショーグンまで！？\nみなさん、アリガトウゴザイマシタ！\nこの喜び、忍法で表現シマスよ～？\nシュバ、シュババ、シュバババ～♪", 10, 19814, 11, 19814101, 0.5);
