INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106011, 1, 1, "なにこれ、ケーキ？\nもしかして、あたしの誕生日の……！？\nいや、もし違ってたらバカみたいだし、\n喜ぶのはちゃんと確認してからに……", 10, 20014, 11, 20014063, 0.5);
