INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, 0.2, 106011, 1, "wac_birthday_shock_loop", "wac_birthday_shock_in", 0, 20014, 3, 20014071, "");
