INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106011, 1, 1, "ひゃあ～っ！？\nなんなのよ、びっくりするじゃない！？\nっていうか……えっと、その！\nこれ、やっぱりあたしのなの？", 10, 20014, 11, 20014073, 0.5);
