INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 105911, 1, 1, "もちろん、キャルさまのでございます。\n【美食殿】全員で心を込めて\nご用意させていただいた、特製の\n手作りケーキとなっております。", 10, 20014, 11, 20014080, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 20014, 91, 20014081, "");
