INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106011, 1, 1, "そっか……えへへ……♪\nなら、最初っからそう言いなさいよ。\nそしたら素直にお礼だって言えるし。\n……うん、ありがとう♪", 10, 20014, 11, 20014085, 0.5);
