INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106011, 1, 1, "撤回！　さっきのお礼はぜ～んぶ撤回！\nなんでまた魔物料理なわけ！？\nあんたたち、年に一度の誕生日くらい\nまともなもん食べさせなさいよ～！！", 10, 20014, 11, 20014095, 0.5);
