INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100811, 1, 1, "どうもありがとう♪\nそれにしても素晴らしいケーキだね、\nボクのために用意してくれたの？", 10, 23814, 11, 23814084, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 23814, 91, 23814085, "");
