INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 104711, 1, 1, "今日は、こんな盛大なお祝いを\n開いてくれるなんてね。\n個人としても、団長としても、\nすごくうれしいよ。", 10, 25314, 11, 25314070, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 25314, 91, 25314071, "");
