INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 107111, 1, 1, "当然だな☆\nこのクリスティーナが全て段取りを\nつけたのだ、満足できないはずがない！", 10, 25314, 11, 25314075, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 25314, 91, 25314076, "");
