INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_26214", "", 0, "vo_wac_26214_003", 0, 26214, 21, 26214077, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 102611, 1, 1, "そ、そりゃあしおりんのためだったら、\nあたしだって、がんばるよ。\nほんと、おめでとうしおりん。\nいつもありがとね。", 10, 26214, 11, 26214078, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 26214, 91, 26214079, "");
