INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 101411, 1, 1, "そ、そんなに急かさなくても……！\nというか助手くんも来てくれたのかい？\nわざわざ祝いに来てくれるなんて、\nその……うん、すごく、うれしいよ。", 10, 26224, 11, 26224083, 0.5);
