INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 107111, 1, 1, "ふふん、マツリちゃんもまた一歩、\nワタシに近づいたということだ。\n良かったな、これからも\nビシバシ鍛えてやるから期待していろ♪", 10, 28414, 11, 28414078, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 28414, 91, 28414079, "");
