INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 109211, 1, 1, "これって私の誕生日ケーキだよね！？\nみんなで用意してくれたの！？\nもしかして愛情たっぷりの手作り！？\nかわいー！　美味しそうー！", 10, 29014, 11, 29014058, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 29014, 91, 29014059, "");
