INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_29014", "", 0, "vo_wac_29014_001", 0, 29014, 21, 29014062, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 109411, 1, 1, "ふふっ、喜んでもらえて良かった……\nアンのそんな顔が見たくて……\nがんばってみたの。\n……ね、ルゥ？", 10, 29014, 11, 29014063, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 29014, 91, 29014064, "");
