INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", 109311, "", "", "wac_birthday_talk_smile", 1, 29014, 3, 29014066, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_29014", "", 0, "vo_wac_29014_002", 0, 29014, 21, 29014067, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 109311, 1, 1, "そうですよー！\nルゥは今回も大活躍だったんですよ！\n材料をぐるぐるかき混ぜたり、\nかき混ぜたり、かき混ぜたりしました！", 10, 29014, 11, 29014068, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 29014, 91, 29014069, "");
