INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_30314", "", 0, "vo_wac_30314_000", 0, 30314, 21, 30314064, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106411, 1, 1, "えっと、私の誕生日をお祝いしてくれて\nありがとう。こんなふうに、\n誰かにお祝いしてもらえるなんて\n思ってなかったわ。", 10, 30314, 11, 30314065, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 30314, 91, 30314066, "");
