INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", 105811, "", "", "wac_birthday_talk_smile", 1, 30314, 3, 30314068, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_30314", "", 0, "vo_wac_30314_001", 0, 30314, 21, 30314069, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 105811, 1, 1, "お祝いするに決まってますよ～！\nシェフィちゃんは【美食殿】の大切な\n仲間なんですから♪", 10, 30314, 11, 30314070, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 30314, 91, 30314071, "");
