INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", 106411, "", "", "wac_birthday_talk_sad", 1, 30314, 3, 30314073, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_30314", "", 0, "vo_wac_30314_002", 0, 30314, 21, 30314074, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106411, 1, 1, "でも、たくさん迷惑をかけているし。\nこんなふうにお祝いをしてもらう\n資格なんて……私には……", 10, 30314, 11, 30314075, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 30314, 91, 30314076, "");
