INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_30314", "", 0, "vo_wac_30314_003", 0, 30314, 21, 30314079, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 106011, 1, 1, "そうよね～、迷惑かけまくりよね～？\nお腹が空いたらすぐ泣くし、目についた\n物はなんでも口に入れちゃうし。", 10, 30314, 11, 30314080, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 30314, 91, 30314081, "");
