INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 101511, 1, 1, "うん、おめでとう～♪\nみんなでケーキも用意したから、\n楽しくお祝いしましょうね～\nほら、アオイちゃんも。", 10, 31314, 11, 31314063, 0.5);
