INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 104011, 1, 1, "お、おお、おめでとうございます！\n私のようなぼっちが、陽の者である\nハツネさんの誕生日をお祝いするのは、\n恐れ多い感じではあるんですが！", 10, 31314, 11, 31314068, 0.5);
