INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", 103811, "", "", "wac_birthday_talk_wish", 1, 32114, 3, 32114073, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "vo_wac_32114", "", 0, "vo_wac_32114_002", 0, 32114, 21, 32114074, "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 103811, 1, 1, "変に遠慮しないでくださいね？\nみんな、リンちゃんのことを\nお祝いしたくて、張り切って\n準備したんですから。", 10, 32114, 11, 32114075, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 32114, 91, 32114076, "");
