INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 101611, 1, 1, "ミサキっち、ホントおめでと～！\nとりま、飲み物はコーヒーでよさげ？\nお店で大人っぽい味でよろ～って\n頼んだら、おに苦くされたけど！", 10, 32314, 11, 32314063, 0.5);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 0, "", "", "", "", 32314, 91, 32314064, "");
