INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 0, 100311, 1, 1, "今日は、こんな素敵な誕生日ケーキを\n用意してくれてありがとう。\nその……すまない、なんだか\n照れくさくて、上手く話せないな。", 10, 33214, 11, 33214058, 0.5);
